(2, 'SAT', '', 'Superintendencia de Administración Tributaria - Administración de impuestos', '', '', '', '', '', '', false, '', '{}', NULL, '2025-10-22 03:12:23.842422+00', '2025-10-22 03:12:23.842422+00', NULL),
(3, 'MSPAS', 'Ministerio de Salud Pública y Asistencia Social', 'Insitución encargada formular las políticas y hacer cumplir la salud preventiva y curativa y a las acciones de protección, promoción, recuperación y rehabilitación de la salud física y mental de los habitantes del país y a la preservación higiénica de medio ambiente', 'https://www.mspas.gob.gt/index.php/servicios', '2444 7474', '', '6ta. Av. 3-45 zona 11, Guatemala', '8:00 hrs a 17:00 hrs', 'Ejercer la rectoría del Sector Salud con la participación social, para proveer servicios de atención integral a la población, con equidad y calidad mediante el funcionamiento de redes integradas de salud en sus tres niveles, con el uso eficiente y transparente de los recursos, para garantizar el derecho a la salud.', true, 'https://www.facebook.com/MinisteriodeSaludPublicayAsistenciaSocial/', '{}', NULL, '2025-10-22 03:12:23.842422+00', '2025-10-22 03:19:43.871983+00', NULL),
(4, 'MARN', 'Ministerio de Ambiente y Recursos Naturales', 'Institución encargada de proteger y fomentar los recursos, bienes y servicios naturales públicos. Tambien regula la gestion ambiental y el desarrollo sostenible.', 'http://www.marn.gob.gt', '24230500', 'rpublicas@marn.gob.gt', '7 avenida 03-67, zona 13, Ciudad Guatemala', '8:00 hrs a 16:30 hrs', 'Somos la institución que regula la gestión ambiental y promueve el desarrollo sostenible en Guatemala, de forma participativa.', true, 'https://www.facebook.com/marngtambiente/', '{}', NULL, '2025-10-22 03:12:23.842422+00', '2025-10-22 03:18:49.702422+00', NULL),
